import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const Sidebar = () => {

  const navigate = useNavigate();
  const location = useLocation();

  const user = JSON.parse(localStorage.getItem("user"));


  // =========================
  // LOGOUT
  // =========================

  const logout = () => {

    localStorage.removeItem("token");

    localStorage.removeItem("user");

    navigate("/login");

  };



  // =========================
  // MENUS
  // =========================


  const freelancerMenu = [

    { name: "Dashboard", path: "/freelancer/dashboard" },

    { name: "Find Projects", path: "/freelancer/projects" },

    { name: "My Proposals", path: "/freelancer/proposals" },

    { name: "Profile", path: "/freelancer/profile" },

  ];



  const clientMenu = [

    { name: "Dashboard", path: "/client/dashboard" },

    { name: "Post Project", path: "/client/post-project" },

    { name: "My Projects", path: "/client/my-projects" },

    { name: "Freelancers", path: "/client/freelancers" },

  ];



  const adminMenu = [

    { name: "Dashboard", path: "/admin/dashboard" },

    { name: "Manage Users", path: "/admin/users" },

    { name: "Manage Projects", path: "/admin/projects" },

    { name: "Reports", path: "/admin/reports" },

  ];



  let menu = [];



  if (user?.role === "freelancer") menu = freelancerMenu;

  if (user?.role === "client") menu = clientMenu;

  if (user?.role === "admin") menu = adminMenu;



  return (

    <div className="w-64 h-screen bg-gradient-to-b from-gray-900 to-gray-800 text-white fixed flex flex-col justify-between">


      {/* TOP SECTION */}

      <div>


        {/* LOGO */}

        <div className="p-6 border-b border-gray-700">

          <h1

            onClick={() => navigate("/")}

            className="text-2xl font-bold cursor-pointer text-green-400"

          >

            Freelancing

          </h1>

        </div>



        {/* USER INFO */}

        <div className="p-6 border-b border-gray-700">

          <div className="flex items-center space-x-3">

            <div className="bg-green-500 w-10 h-10 rounded-full flex items-center justify-center font-bold">

              {user?.name?.charAt(0)}

            </div>

            <div>

              <p className="font-semibold">

                {user?.name}

              </p>

              <p className="text-sm text-gray-400 capitalize">

                {user?.role}

              </p>

            </div>

          </div>

        </div>



        {/* MENU */}

        <ul className="p-6 space-y-3">

          {menu.map((item, index) => (

            <li

              key={index}

              onClick={() => navigate(item.path)}

              className={`

              cursor-pointer p-3 rounded-lg transition

              hover:bg-gray-700

              ${location.pathname === item.path

                  ? "bg-green-500"

                  : ""

                }

              `}

            >

              {item.name}

            </li>

          ))}

        </ul>


      </div>



      {/* LOGOUT */}

      <div className="p-6">

        <button

          onClick={logout}

          className="w-full bg-red-500 hover:bg-red-600 p-3 rounded-lg"

        >

          Logout

        </button>

      </div>



    </div>

  );

};


export default Sidebar;
